    {"path": "elden-ring-mod-manager/src/mod_manager.py", "content": "\"\"\"Core module for managing Elden Ring mod installations.\n\nHandles mod discovery, backup, installation, and validation for Elden Ring.\n\"\"\"\n\nimport os\nimport shutil\nimport json\nfrom pathlib import Path\nfrom typing import List, Dict, Optional\nfrom dataclasses import dataclass, asdict\n\n\n@dataclass\nclass ModInfo:\n    \"\"\"Represents metadata about an Elden Ring mod.\"\"\"\n    name: str\n    version: str\n    author: str\n    description: str\n    game_version: str  # e.g., \"1.12.3\"\n    install_path: str   # relative path inside game directory\n    checksum: Optional[str] = None\n\n\nclass ModManager:\n    \"\"\"Main manager class for Elden Ring mod operations.\"\"\"\n\n    def __init__(self, game_path: str = None, mods_dir: str = None):\n        \"\"\"\n        Initialize the mod manager.\n\n        Args:\n            game_path: Path to Elden Ring installation (default: auto-detect)\n            mods_dir: Directory to store mod configurations (default: ./mods)\n        \"\"\"\n        self.game_path = Path(game_path) if game_path else self._find_game_path()\n        self.mods_dir = Path(mods_dir) if mods_dir else Path.cwd() / \"mods\"\n        self.mods_dir.mkdir(parents=True, exist_ok=True)\n        self.installed_mods: Dict[str, ModInfo] = {}\n        self._load_mod_registry()\n\n    def _find_game_path(self) -> Path:\n        \"\"\"Attempt to locate Elden Ring installation on common platforms.\"\"\"\n        common_paths = [\n            Path(\"C:/Program Files (x86)/Steam/steamapps/common/ELDEN RING/Game\"),\n            Path(\"~/Library/Application Support/Steam/steamapps/common/ELDEN RING/Game\").expanduser(),\n            Path(\"~/.steam/steam/steamapps/common/ELDEN RING/Game\").expanduser(),\n        ]\n        for path in common_paths:\n            if path.exists() and (path / \"elden_ring.exe\").exists():\n                return path\n        raise FileNotFoundError(\"Could not locate Elden Ring installation. Specify game_path manually.\")\n\n    def _load_mod_registry(self):\n        \"\"\"Load installed mods from JSON registry.\"\"\"\n        registry_file = self.mods_dir / \"registry.json\"\n        if registry_file.exists():\n            with open(registry_file, \"r\") as f:\n                data = json.load(f)\n                self.installed_mods = {k: ModInfo(**v) for k, v in data.items()}\n\n    def _save_mod_registry(self):\n        \"\"\"Save installed mods to JSON registry.\"\"\"\n        registry_file = self.mods_dir / \"registry.json\"\n        with open(registry_file, \"w\") as f:\n            data = {k: asdict(v) for k, v in self.installed_mods.items()}\n            json.dump(data, f, indent=2)\n\n    def discover_mods(self) -> List[ModInfo]:\n        \"\"\"\n        Scan the mods directory for available mod packages.\n\n        Returns:\n            List of discovered ModInfo objects from .mod files.\n        \"\"\"\n        discovered = []\n        for mod_file in self.mods_dir.glob(\"*.mod\"):\n            try:\n                with open(mod_file, \"r\") as f:\n                    data = json.load(f)\n                    mod = ModInfo(**data)\n                    discovered.append(mod)\n            except (json.JSONDecodeError, KeyError) as e:\n                print(f\"Warning: Could not parse {mod_file.name}: {e}\")\n        return discovered\n\n    def install_mod(self, mod: ModInfo, backup: bool = True) -> bool:\n        \"\"\"\n        Install a mod into the Elden Ring game directory.\n\n        Args:\n            mod: The mod to install\n            backup: Whether to create a backup of original files\n\n        Returns:\n            True if installation succeeded, False otherwise.\n        \"\"\"\n        target_path = self.game_path / mod.install_path\n        if not target_path.parent.exists():\n            print(f\"Error: Target directory {target_path.parent} does not exist.\")\n            return False\n\n        # Backup original if requested and not already backed up\n        backup_dir = self.mods_dir / \"backups\"\n        if backup and target_path.exists():\n            backup_path = backup_dir / f\"{mod.name}_original_{target_path.name}\"\n            if not backup_path.exists():\n                backup_dir.mkdir(parents=True, exist_ok=True)\n                shutil.copy2(target_path, backup_path)\n                print(f\"Backed up {target_path.name} to {backup_path}\")\n\n        # Simulate mod installation (in real project, would copy mod files)\n        print(f\"Installing mod '{mod.name}' v{mod.version} to {target_path}\")\n        self.installed_mods[mod.name] = mod\n        self._save_mod_registry()\n        return True\n\n    def uninstall_mod(self, mod_name: str, restore_backup: bool = True) -> bool:\n        \"\"\"\n        Uninstall a mod and optionally restore the original file.\n\n        Args:\n            mod_name: Name of the mod to uninstall\n            restore_backup: Whether to restore from backup\n\n        Returns:\n            True if uninstallation succeeded, False otherwise.\n        \"\"\"\n        mod = self.installed_mods.get(mod_name)\n        if not mod:\n            print(f\"Error: Mod '{mod_name}' is not installed.\")\n            return False\n\n        target_path = self.game_path / mod.install_path\n        if restore_backup:\n            backup_path = self.mods_dir / \"backups\" / f\"{mod_name}_original_{target_path.name}\"\n            if backup_path.exists():\n                shutil.copy2(backup_path, target_path)\n                print(f\"Restored original file for {mod_name}\")\n                backup_path.unlink()\n            else:\n                print(f\"Warning: No backup found for {mod_name}, removing mod file.\")\n                if target_path.exists():\n                    target_path.unlink()\n\n        del self.installed_mods[mod_name]\n        self._save_mod_registry()\n        print(f\"Uninstalled mod '{mod_name}'\")\n        return True\n\n    def validate_game_files(self) -> List[str]:\n        \"\"\"\n        Check integrity of game files against known mods.\n\n        Returns:\n            List of issues found (empty if all good).\n        \"\"\"\n        issues = []\n        for mod_name, mod in self.installed_mods.items():\n            target_path = self.game_path / mod.install_path\n            if not target_path.exists():\n                issues.append(f\"Mod '{mod_name}' expects file {mod.install_path} but it's missing.\")\n        return issues\n\n    def list_installed(self) -> List[str]:\n        \"\"\"Return list of installed mod names.\"\"\"\n        return list(self.installed_mods.keys())\n"},
    {"path": "elden-ring-mod-manager/src/nexus_api.py", "content": "\"\"\"Module for interacting with Nexus Mods API to fetch Elden Ring mods.\"\"\"\n\nimport requests\nfrom typing import List, Dict, Optional\nfrom dataclasses import dataclass\n\n\n@dataclass\nclass NexusMod:\n    \"\"\"Represents a mod from Nexus Mods API.\"\"\"\n    mod_id: int\n    name: str\n    summary: str\n    version: str\n    author: str\n    download_count: int\n    mod_url: str\n\n\nclass NexusAPIClient:\n    \"\"\"Client for Nexus Mods API v1.\"\"\"\n\n    BASE_URL = \"https://api.nexusmods.com/v1\"\n    GAME_DOMAIN = \"eldenring\"\n\n    def __init__(self, api_key: str):\n        \"\"\"\n        Initialize the API client.\n\n        Args:\n            api_key: Nexus Mods API key (required for authenticated requests)\n        \"\"\"\n        self.api_key = api_key\n        self.headers = {\n            \"apikey\": api_key,\n            \"User-Agent\": \"EldenRingModManager/1.0 (contact@example.com)\"\n        }\n\n    def search_mods(self, query: str, limit: int = 20) -> List[NexusMod]:\n        \"\"\"\n        Search for Elden Ring mods on Nexus Mods.\n\n        Args:\n            query: Search term\n            limit: Maximum number of results (max 50)\n\n        Returns:\n            List of NexusMod objects matching the query.\n        \"\"\"\n        url = f\"{self.BASE_URL}/games/{self.GAME_DOMAIN}/mods/search.json\"\n        params = {\n            \"search\": query,\n            \"limit\": min(limit, 50)\n        }\n        try:\n            response = requests.get(url, headers=self.headers, params=params, timeout=10)\n            response.raise_for_status()\n            data = response.json()\n            mods = []\n            for item in data.get(\"data\", []):\n                mod = NexusMod(\n                    mod_id=item[\"mod_id\"],\n                    name=item[\"name\"],\n                    summary=item[\"summary\"],\n                    version=item[\"version\"],\n                    author=item.get(\"author\", \"Unknown\"),\n                    download_count=item.get(\"downloads\", 0),\n                    mod_url=item.get(\"url\", \"\")\n                )\n                mods.append(mod)\n            return mods\n        except requests.RequestException as e:\n            print(f\"API request failed: {e}\")\n            return []\n\n    def get_mod_details(self, mod_id: int) -> Optional[NexusMod]:\n        \"\"\"\n        Get detailed information about a specific mod.\n\n        Args:\n            mod_id: Nexus Mods mod ID\n\n        Returns:\n            NexusMod object if found, None otherwise.\n        \"\"\"\n        url = f\"{self.BASE_URL}/games/{self.GAME_DOMAIN}/mods/{mod_id}.json\"\n        try:\n            response = requests.get(url, headers=self.headers, timeout=10)\n            response.raise_for_status()\n            data = response.json()\n            return NexusMod(\n                mod_id=data[\"mod_id\"],\n                name=data[\"name\"],\n                summary=data[\"summary\"],\n                version=data[\"version\"],\n                author=data.get(\"author\", \"Unknown\"),\n                download_count=data.get(\"downloads\", 0),\n                mod_url=data.get(\"url\", \"\")\n            )\n        except requests.RequestException as e:\n            print(f\"Failed to fetch mod {mod_id}: {e}\")\n            return None\n"},
    {"path": "elden-ring-mod-manager/src/mod_utils.py", "content": "\"\"\"Utility functions for Elden Ring mod file operations.\"\"\"\n\nimport hashlib\nimport os\nfrom pathlib import Path\nfrom typing import Optional\n\n\ndef calculate_file_checksum(file_path: str, algorithm: str = \"sha256\") -> Optional[str]:\n    \"\"\"\n    Calculate checksum of a file for integrity verification.\n\n    Args:\n        file_path: Path to the file\n        algorithm: Hash algorithm (sha256, md5, etc.)\n\n    Returns:\n        Hexadecimal checksum string, or None if file not found.\n    \"\"\"\n    path = Path(file_path)\n    if not path.exists() or not path.is_file():\n        return None\n\n    hash_func = hashlib.new(algorithm)\n    with open(path, \"rb\") as f:\n        for chunk in iter(lambda: f.read(8192), b\"\"):\n            hash_func.update(chunk)\n    return hash_func.hexdigest()\n\n\ndef verify_mod_integrity(mod_file: str, expected_checksum: str) -> bool:\n    \"\"\"\n    Verify a mod file matches its expected checksum.\n\n    Args:\n        mod_file: Path to the mod file\n        expected_checksum: Expected SHA256 checksum\n\n    Returns:\n        True if checksums match, False otherwise.\n    \"\"\"\n    actual = calculate_file_checksum(mod_file)\n    if actual is None:\n        return False\n    return actual.lower() == expected_checksum.lower()\n\n\ndef get_game_version(game_path: str) -> Optional[str]:\n    \"\"\"\n    Detect the installed version of Elden Ring.\n\n    Args:\n        game_path: Path to the game directory\n\n    Returns:\n        Version string (e.g., \"1.12.3\") or None if undetectable.\n    \"\"\"\n    # In a real project, this would parse the game executable or registry\n    # For demonstration, we check a known file\n    exe_path = Path(game_path) / \"elden_ring.exe\"\n    if not exe_path.exists():\n        return None\n    \n    # Simulated version detection (real implementation would use file metadata)\n    # Placeholder: check file modification date to infer version\n    mtime = exe_path.stat().st_mtime\n    # This is a dummy mapping; real project would use proper detection\n    if mtime > 1700000000:  # After Nov 2023\n        return \"1.10.0\"\n    return \"1.09.0\"\n\n\ndef create_mod_backup(source_path: str, backup_dir: str) -> Optional[str]:\n    \"\"\"\n    Create a backup of a file before mod installation.\n\n    Args:\n        source_path: Original file to back up\n        backup_dir: Directory to store backup\n\n    Returns:\n        Path to backup file, or None on failure.\n    \"\"\"\n    src = Path(source_path)\n    if not src.exists():\n        return None\n\n    backup_path = Path(backup_dir) / f\"backup_{src.name}\"\n    backup_path.parent.mkdir(parents=True, exist_ok=True)\n    \n    import shutil\n    shutil.copy2(src, backup_path)\n    return str(backup_path)\n"},
